import{_ as o,o as i,c as a,ai as d}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"语音浮层","description":"","frontmatter":{"read_when":["调整语音浮层行为"],"summary":"唤醒词与按键说话重叠时的语音浮层生命周期","title":"语音浮层","x-i18n":{"generated_at":"2026-02-01T21:33:26Z","model":"claude-opus-4-5","provider":"pi","source_hash":"3be1a60aa7940b2368ff62cd49f04b2b8422876030e8ea206b467f66a5a6bd4d","source_path":"platforms/mac/voice-overlay.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/voice-overlay.md","filePath":"zh-CN/platforms/mac/voice-overlay.md","lastUpdated":1771906665000}'),l={name:"zh-CN/platforms/mac/voice-overlay.md"};function c(s,e,t,r,n,h){return i(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="语音浮层生命周期-macos" tabindex="-1"><a class="header-anchor" href="#语音浮层生命周期-macos">#</a> 语音浮层生命周期（macOS）</h1><p>受众：macOS 应用贡献者。目标：在唤醒词与按键说话重叠时保持语音浮层行为可预测。</p><h3 id="当前意图" tabindex="-1"><a class="header-anchor" href="#当前意图">#</a> 当前意图</h3><ul><li>如果浮层已因唤醒词显示，此时用户按下热键，热键会话会<em>接管</em>现有文本而非重置。浮层在热键按住期间保持显示。用户松开时：如果有去除空白后的文本则发送，否则关闭。</li><li>单独使用唤醒词时仍在静音后自动发送；按键说话在松开时立即发送。</li></ul><h3 id="已实现-2025-年-12-月-9-日" tabindex="-1"><a class="header-anchor" href="#已实现-2025-年-12-月-9-日">#</a> 已实现（2025 年 12 月 9 日）</h3><ul><li>浮层会话现在为每次捕获（唤醒词或按键说话）携带一个令牌。当令牌不匹配时，部分/最终/发送/关闭/音量更新会被丢弃，避免过时回调。</li><li>按键说话会接管任何可见的浮层文本作为前缀（因此在唤醒浮层显示时按下热键会保留文本并追加新语音）。它最多等待 1.5 秒获取最终转录结果，然后回退到当前文本。</li><li>提示音/浮层日志以 <code>info</code> 级别输出，分类为 <code>voicewake.overlay</code>、<code>voicewake.ptt</code> 和 <code>voicewake.chime</code>（会话开始、部分、最终、发送、关闭、提示音原因）。</li></ul><h3 id="后续步骤" tabindex="-1"><a class="header-anchor" href="#后续步骤">#</a> 后续步骤</h3><ol><li><strong>VoiceSessionCoordinator（actor）</strong><ul><li>同一时间只拥有一个 <code>VoiceSession</code>。</li><li>API（基于令牌）：<code>beginWakeCapture</code>、<code>beginPushToTalk</code>、<code>updatePartial</code>、<code>endCapture</code>、<code>cancel</code>、<code>applyCooldown</code>。</li><li>丢弃携带过时令牌的回调（防止旧识别器重新打开浮层）。</li></ul></li><li><strong>VoiceSession（模型）</strong><ul><li>字段：<code>token</code>、<code>source</code>（wakeWord|pushToTalk）、已提交/临时文本、提示音标志、计时器（自动发送、空闲）、<code>overlayMode</code>（display|editing|sending）、冷却截止时间。</li></ul></li><li><strong>浮层绑定</strong><ul><li><code>VoiceSessionPublisher</code>（<code>ObservableObject</code>）将活跃会话镜像到 SwiftUI。</li><li><code>VoiceWakeOverlayView</code> 仅通过 publisher 渲染；绝不直接修改全局单例。</li><li>浮层用户操作（<code>sendNow</code>、<code>dismiss</code>、<code>edit</code>）携带会话令牌回调到 coordinator。</li></ul></li><li><strong>统一发送路径</strong><ul><li><code>endCapture</code> 时：如果去除空白后文本为空 → 关闭；否则 <code>performSend(session:)</code>（播放一次发送提示音、转发、关闭）。</li><li>按键说话：无延迟；唤醒词：可选自动发送延迟。</li><li>按键说话结束后对唤醒运行时施加短暂冷却，防止唤醒词立即重新触发。</li></ul></li><li><strong>日志</strong><ul><li>Coordinator 在子系统 <code>ai.opensoul</code>、分类 <code>voicewake.overlay</code> 和 <code>voicewake.chime</code> 下输出 <code>.info</code> 级别日志。</li><li>关键事件：<code>session_started</code>、<code>adopted_by_push_to_talk</code>、<code>partial</code>、<code>finalized</code>、<code>send</code>、<code>dismiss</code>、<code>cancel</code>、<code>cooldown</code>。</li></ul></li></ol><h3 id="调试清单" tabindex="-1"><a class="header-anchor" href="#调试清单">#</a> 调试清单</h3><ul><li><p>复现浮层粘滞问题时流式查看日志：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> log</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> stream</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --predicate</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;subsystem == &quot;ai.opensoul&quot; AND category CONTAINS &quot;voicewake&quot;&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --level</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> info</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --style</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> compact</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p>验证只有一个活跃会话令牌；过时回调应被 coordinator 丢弃。</p></li><li><p>确保按键说话松开时始终使用活跃令牌调用 <code>endCapture</code>；如果文本为空，预期 <code>dismiss</code> 且不播放提示音或发送。</p></li></ul><h3 id="迁移步骤-建议" tabindex="-1"><a class="header-anchor" href="#迁移步骤-建议">#</a> 迁移步骤（建议）</h3><ol><li>添加 <code>VoiceSessionCoordinator</code>、<code>VoiceSession</code> 和 <code>VoiceSessionPublisher</code>。</li><li>重构 <code>VoiceWakeRuntime</code>，使其创建/更新/结束会话，而非直接操作 <code>VoiceWakeOverlayController</code>。</li><li>重构 <code>VoicePushToTalk</code>，使其接管现有会话并在松开时调用 <code>endCapture</code>；施加运行时冷却。</li><li>将 <code>VoiceWakeOverlayController</code> 连接到 publisher；移除来自 runtime/PTT 的直接调用。</li><li>添加会话接管、冷却和空文本关闭的集成测试。</li></ol>',12)])])}const k=o(l,[["render",c]]);export{u as __pageData,k as default};
